function recursiveSound(sec: Sector | null | undefined, soundBlocks: number): void {
  if (sec === null || sec === undefined) {
    console.warn('recursiveSound called with null sector, skipping');
    return;
  }
  if (soundBlocks < 0 || soundBlocks > 1) {
    console.warn(`Invalid soundBlocks value: ${soundBlocks}`);
    return;
  }
  if (sec.validCount === validCount && sec.soundTraversed <= soundBlocks + 1) {
    return; // already flooded
  }
  sec.validCount = validCount;
  sec.soundTraversed = soundBlocks + 1;
  sec.soundTarget = soundTarget;
}
